DROP TABLE IF EXISTS `faas_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `faas_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `arf_no` varchar(50) DEFAULT NULL,
  `pin` varchar(50) DEFAULT NULL,
  `oct_tct_no` varchar(50) DEFAULT NULL,
  `cln` varchar(70) DEFAULT NULL,
  `owner_name` varchar(255) NOT NULL,
  `owner_address` text,
  `owner_barangay` varchar(100) DEFAULT NULL,
  `owner_municipality` varchar(100) DEFAULT NULL,
  `owner_province` varchar(100) DEFAULT NULL,
  `administrator_name` varchar(255) DEFAULT NULL,
  `administrator_address` text,
  `owner_administrator` varchar(255) DEFAULT NULL,
  `property_location` text,
  `property_barangay` varchar(100) DEFAULT NULL,
  `property_municipality` varchar(100) DEFAULT NULL,
  `property_province` varchar(100) DEFAULT NULL,
  `north_boundary` text,
  `south_boundary` text,
  `east_boundary` text,
  `west_boundary` text,
  `classification` varchar(100) DEFAULT NULL,
  `sub_class` varchar(100) DEFAULT NULL,
  `area` decimal(15,2) DEFAULT NULL,
  `unit_value_land` decimal(15,2) DEFAULT NULL,
  `product_class` varchar(100) DEFAULT NULL,
  `improvement_qty` int DEFAULT NULL,
  `unit_value_improvement` decimal(15,2) DEFAULT NULL,
  `market_value_improvement` decimal(15,2) DEFAULT NULL,
  `adj_factor` decimal(5,2) DEFAULT NULL,
  `percent_adjustment` decimal(5,2) DEFAULT NULL,
  `value_adjustment` decimal(15,2) DEFAULT NULL,
  `adjusted_market_value` decimal(15,2) DEFAULT NULL,
  `kind` varchar(100) DEFAULT NULL,
  `actual_use` varchar(100) DEFAULT NULL,
  `market_value_detail` decimal(15,2) DEFAULT NULL,
  `assessment_level` decimal(5,2) DEFAULT NULL,
  `assessed_value_detail` decimal(15,2) DEFAULT NULL,
  `land_appraisal_total` decimal(15,2) DEFAULT NULL,
  `improvements_total` decimal(15,2) DEFAULT NULL,
  `adjustment_total` decimal(15,2) DEFAULT NULL,
  `assessment_total` decimal(15,2) DEFAULT NULL,
  `assessed_value` decimal(15,2) DEFAULT NULL,
  `market_value` decimal(15,2) DEFAULT NULL,
  `effectivity_date` date DEFAULT NULL,
  `effectivity_year` varchar(10) DEFAULT NULL,
  `taxability` varchar(50) DEFAULT NULL,
  `tax_rate` decimal(5,2) DEFAULT NULL,
  `previous_td_no` varchar(50) DEFAULT NULL,
  `previous_owner` varchar(255) DEFAULT NULL,
  `previous_av_land` decimal(15,2) DEFAULT NULL,
  `previous_av_improvements` decimal(15,2) DEFAULT NULL,
  `previous_total_av` decimal(15,2) DEFAULT NULL,
  `memoranda` text,
  `status` enum('draft','for_approval','approved','rejected') DEFAULT 'draft',
  `hidden` tinyint DEFAULT '0',
  `encoder_id` int DEFAULT NULL,
  `approver_id` int DEFAULT NULL,
  `approval_date` timestamp NULL DEFAULT NULL,
  `rejection_reason` text,
  `excel_file_path` varchar(500) DEFAULT NULL,
  `pdf_preview_path` varchar(500) DEFAULT NULL,
  `unirrig_pdf_preview_path` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `unirrig_excel_file_path` varchar(255) DEFAULT NULL,
  `land_appraisals_json` json DEFAULT NULL,
  `improvements_json` json DEFAULT NULL,
  `market_values_json` json DEFAULT NULL,
  `assessments_json` json DEFAULT NULL,
  `memoranda_label` varchar(100) DEFAULT 'MEMORANDA:',
  `memoranda_code` varchar(50) DEFAULT NULL,
  `memoranda_paragraph` text,
  `previous_td_no2` varchar(100) DEFAULT NULL,
  `previous_owner2` varchar(255) DEFAULT NULL,
  `previous_av_land2` decimal(15,2) DEFAULT NULL,
  `previous_av_improvements2` decimal(15,2) DEFAULT NULL,
  `rw_row` varchar(10) DEFAULT NULL,
  `ctc_no` varchar(100) DEFAULT NULL,
  `ctc_issued_on` date DEFAULT NULL,
  `ctc_issued_at` varchar(255) DEFAULT NULL,
  `parent_id` int DEFAULT NULL,
  `updated_by` int DEFAULT NULL,
  `released_at` timestamp NULL DEFAULT NULL,
  `released_by` int DEFAULT NULL,
  `unirrig_plain_excel_path` varchar(500) DEFAULT NULL,
  `unirrig_plain_pdf_path` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `pin_UNIQUE` (`pin`),
  UNIQUE KEY `oct_tct_no_UNIQUE` (`oct_tct_no`),
  KEY `encoder_id` (`encoder_id`),
  KEY `approver_id` (`approver_id`),
  KEY `idx_hidden` (`hidden`),
  KEY `idx_faas_status_hidden` (`status`,`hidden`),
  KEY `idx_faas_encoder_hidden` (`encoder_id`,`hidden`),
  KEY `idx_faas_created_at` (`created_at`),
  KEY `idx_faas_arf_no` (`arf_no`),
  KEY `idx_faas_pin` (`pin`),
  KEY `fk_parent_record` (`parent_id`),
  KEY `fk_updated_by` (`updated_by`),
  KEY `fk_released_by` (`released_by`),
  CONSTRAINT `faas_records_ibfk_1` FOREIGN KEY (`encoder_id`) REFERENCES `users` (`id`),
  CONSTRAINT `faas_records_ibfk_2` FOREIGN KEY (`approver_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_parent_record` FOREIGN KEY (`parent_id`) REFERENCES `faas_records` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_released_by` FOREIGN KEY (`released_by`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_updated_by` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=713 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

